7	
8	import { isPasswordValid } from "@calcom/lib/auth/isPasswordValid";
9	import { WEBSITE_URL } from "@calcom/lib/constants";
10	import { emailRegex } from "@calcom/lib/emailSchema";
11	import { useLocale } from "@calcom/lib/hooks/useLocale";
12	import { Button } from "@calcom/ui/components/button";
13	import { EmptyScreen } from "@calcom/ui/components/empty-screen";
14	import { EmailField, Label, TextField, PasswordField } from "@calcom/ui/components/form";
15	
16	export const AdminUserContainer = (props: React.ComponentProps<typeof AdminUser> & { userCount: number }) => {
17	  const { t } = useLocale();
18	  if (props.userCount > 0)
19	    return (
20	      <form
21	        id="wizard-step-1"
22	        name="wizard-step-1"
23	        className="stack-y-4"
24	        onSubmit={(e) => {
25	          e.preventDefault();
26	          props.onSuccess();
27	        }}>
28	        <EmptyScreen
29	          Icon="user-check"
30	          headline={t("admin_user_created")}
31	          description={t("admin_user_created_description")}
32	        />
33	      </form>
34	    );
35	  return <AdminUser {...props} />;
36	};
37	
38	export const AdminUser = (props: {
39	  onSubmit: () => void;
40	  onError: () => void;
41	  onSuccess: () => void;
42	  nav: { onNext: () => void; onPrev: () => void };
43	}) => {
44	  const { t } = useLocale();
45	
46	  const formSchema = z.object({
47	    username: z
48	      .string()
49	      .refine((val) => val.trim().length >= 1, { message: t("at_least_characters", { count: 1 }) }),
50	    email_address: z.string().regex(emailRegex, { message: t("enter_valid_email") }),
51	    full_name: z.string().min(3, t("at_least_characters", { count: 3 })),
52	    password: z.string().superRefine((data, ctx) => {
53	      const isStrict = true;
54	      const result = isPasswordValid(data, true, isStrict);
55	      Object.keys(result).map((key: string) => {
56	        if (!result[key as keyof typeof result]) {
57	          ctx.addIssue({
58	            code: z.ZodIssueCode.custom,
59	            path: [key],
60	            message: key,
61	          });
62	        }
63	      });
64	    }),
65	  });
66	
67	  type formSchemaType = z.infer<typeof formSchema>;
68	
69	  const formMethods = useForm<formSchemaType>({
70	    mode: "onChange",
71	    resolver: zodResolver(formSchema),
72	  });
73	
74	  const onError = () => {
75	    props.onError();
76	  };
77	
78	  const onSubmit = formMethods.handleSubmit(async (data) => {
79	    props.onSubmit();
80	    const response = await fetch("/api/auth/setup", {
81	      method: "POST",
82	      body: JSON.stringify({
83	        username: data.username.trim(),
84	        full_name: data.full_name,
85	        email_address: data.email_address.toLowerCase(),
86	        password: data.password,
87	      }),
88	      headers: {
89	        "Content-Type": "application/json",
90	      },
91	    });
92	    if (response.status === 200) {
93	      await signIn("credentials", {
94	        redirect: false,
95	        callbackUrl: "/",
96	        email: data.email_address.toLowerCase(),
97	        password: data.password,
98	      });
99	      props.onSuccess();
100	    } else {
101	      props.onError();
102	    }
103	  }, onError);
104	
105	  const longWebsiteUrl = WEBSITE_URL.length > 30;
106	
107	  return (
108	    <FormProvider {...formMethods}>
109	      <form id="wizard-step-1" name="wizard-step-1" className="stack-y-4" onSubmit={onSubmit}>
110	        <div>
111	          <Controller
112	            name="username"
113	            control={formMethods.control}
114	            render={({ field: { onBlur, onChange, value } }) => (
115	              <>
116	                <Label htmlFor="username" className={classNames(longWebsiteUrl && "mb-0")}>
117	                  <span className="block">{t("username")}</span>
118	                  {longWebsiteUrl && (
119	                    <small className="items-centerpx-3 bg-subtle border-default text-subtle mt-2 inline-flex rounded-t-md border border-b-0 px-3 py-1">
120	                      {process.env.NEXT_PUBLIC_WEBSITE_URL}
121	                    </small>
122	                  )}
123	                </Label>
124	                <TextField
125	                  addOnLeading={
126	                    !longWebsiteUrl && (
127	                      <span className="text-subtle inline-flex items-center rounded-none text-sm">
128	                        {process.env.NEXT_PUBLIC_WEBSITE_URL}/
129	                      </span>
130	                    )
131	                  }
132	                  id="username"
133	                  labelSrOnly={true}
134	                  value={value || ""}
135	                  className={classNames("my-0", longWebsiteUrl && "rounded-t-none")}
136	                  onBlur={onBlur}
137	                  name="username"
138	                  onChange={(e) => onChange(e.target.value)}
139	                />
140	              </>
141	            )}
142	          />
143	        </div>
144	        <div>
145	          <Controller
146	            name="full_name"
147	            control={formMethods.control}
148	            render={({ field: { onBlur, onChange, value } }) => (
149	              <TextField
150	                value={value || ""}
151	                onBlur={onBlur}
152	                onChange={(e) => onChange(e.target.value)}
153	                color={formMethods.formState.errors.full_name ? "warn" : ""}
154	                type="text"
155	                name="full_name"
156	                autoCapitalize="none"
157	                autoComplete="name"
158	                autoCorrect="off"
159	                className="my-0"
160	              />
161	            )}
162	          />
163	        </div>
164	        <div>
165	          <Controller
166	            name="email_address"
167	            control={formMethods.control}
168	            render={({ field: { onBlur, onChange, value } }) => (
169	              <EmailField
170	                value={value || ""}
171	                onBlur={onBlur}
172	                onChange={(e) => onChange(e.target.value)}
173	                className="my-0"
174	                name="email_address"
175	              />
176	            )}
177	          />
178	        </div>
179	        <div>
180	          <Controller
181	            name="password"
182	            control={formMethods.control}
183	            render={({ field: { onBlur, onChange, value } }) => (
184	              <PasswordField
185	                value={value || ""}
186	                onBlur={onBlur}
187	                onChange={(e) => onChange(e.target.value)}
188	                hintErrors={["caplow", "admin_min", "num"]}
189	                name="password"
190	                className="my-0"
191	                autoComplete="off"
192	              />
193	            )}
194	          />
195	        </div>
196	        <div className="flex justify-end gap-2">
197	          <Button
198	            type="submit"
199	            color="primary"
200	            loading={formMethods.formState.isSubmitting}
201	            disabled={!formMethods.formState.isValid || formMethods.formState.isSubmitting}>
202	            {t("next")}
203	          </Button>
204	        </div>
205	      </form>
206	    </FormProvider>
207	  );
208	};
